  if (Options & VERBOSE && VerboseFormat=='1')
    fprintf (stderr,"\n");

  /* Record the time so well spent... */
  STOP_TIME                  /* Get trace done time. */
  tused = TIME_ELAPSED       /* Calc. elapsed time. Define TIME_ELAPSED as */
