  /* Clean up and leave */
  display_finished();

  close_all ();

  PRINT_STATS

  if (Options & VERBOSE_FILE)
    {
    stat_file = fopen(Stat_File_Name,"a+t");
    fprintf (stat_file,"Done Tracing\n");
    fclose(stat_file);
    }

  FINISH_POVRAY
  }

/* Print out usage error message */

